{
  "id": "agent_...",
  "name": "Engineering Agent",
  "description": "Can inspect local repos, edit code, run tests, and summarize changes.",
  "model": { "provider": "anthropic", "id": "claude-sonnet-4-5", "speed": "standard" },
  "system": "You are a pragmatic engineering agent...",
  "tools": [
    { "type": "agent_toolset", "configs": { "bash": true, "read": true, "write": true, "edit": true, "grep": true } }
