  ],
  "multiagent": {
    "type": "coordinator",
    "agents": [{ "type": "agent", "id": "agent_reviewer" }]
  },
  "metadata": {}
}

{
  "model": "claude-sonnet-4-5",
  "name": "Repo Engineer",
  "description": "A local engineering agent for repository work.",
  "system": "You inspect code, make minimal edits, and verify changes.",
  "tools": [{ "type": "agent_toolset" }],
  "skills": [{ "type": "local", "skill_id": "lark-doc", "version": "latest" }],
  "metadata": { "owner": "local" }
}

{
  "agent": "agent_123",
  "environment_id": "env_local_dev",
  "title": "Implement auth middleware",
  "vault_ids": ["vault_user_default"],
  "resources": [
    {
      "type": "memory_store",
      "memory_store_id": "memstore_project",
      "access": "read_write",
      "instructions": "Check project conventions before editing code."
    }
  ]
}

{
  "events": [
    {
      "type": "user.message",
      "content": [{ "type": "text", "text": "Read the repo and propose a minimal implementation plan." }]
    }
  ]
}

{
  "intent": "repo_engineering",
  "name": "Go Repo Maintainer",
  "system": "...",
  "recommended_tools": ["read", "grep", "edit", "bash"],
  "recommended_skills": ["github", "lark-doc"],
  "recommended_environment": "mac-local-dev",
  "vault_requirements": [
    { "type": "github_token", "reason": "May need to inspect issues or create PRs." }
  ],
  "risk_notes": [
    "bash and edit should require confirmation outside workspace."
  ]
}
